// UNPATCHED EfspConstructNewPfileHeader (sub_1c0009be8):
rcx_4  = s - a;                    // 32-bit locals
rax_10 = rdx_3 + rcx_4;            // rdx_3 = 32-bit DataOffset+DataLength
if (!(rcx_4>>63) && (rax_10>>63)) rbx = STATUS_INTEGER_OVERFLOW;   // sign check #1
else {
    r14 = rax_10 + 0x20;
    if (rax_10>=0 && (rax_10>>63)!=(r14>>63)) rbx = STATUS_INTEGER_OVERFLOW; // sign check #2
    else if (r14 > 0xffffffff) rbx = STATUS_INTEGER_OVERFLOW;               // 32-bit range check
    else if (r14 >= 0x20)
        P = ExAllocatePoolWithTag(PagedPool, r14, 0x6d736645);            // 0x20 bytes + UUID written into P
}

// PATCHED sub_14000a3a4:
if (sub_14000a810(rdx_3, rcx_4, &acc) >= 0 &&
    sub_14000a810(acc, 0x20, &acc) >= 0) {
    if (acc > 0xffffffff) rbx = STATUS_INTEGER_OVERFLOW;
    else if (acc >= 0x20)
        P = ExAllocatePool2(0x100 /*POOL_FLAG_PAGED*/, acc, 0x6d736645);
}

